188	
189	    // Use the internal function that returns filtered device-maker pairs
190	    auto filtered_pairs = find_filtered_devices_with_makers(hint, filter);
191	
192	    typedef std::tuple<device_addr_t, make_t> dev_addr_make_t;
193	    std::vector<dev_addr_make_t> dev_addr_makers;
194	
195	    // Convert to the expected format (no additional filtering needed)
196	    for (const auto& pair : filtered_pairs) {
197	        dev_addr_makers.push_back(dev_addr_make_t(std::get<0>(pair), std::get<1>(pair)));
198	    }
199	
200	    // check that we found any devices
201	    if (dev_addr_makers.empty()) {
202	        throw uhd::key_error(
203	            std::string("No devices found for ----->\n") + hint.to_pp_string());
204	    }
205	
206	    // check that the which index is valid
207	    if (dev_addr_makers.size() <= which) {
208	        throw uhd::index_error("No device at index " + std::to_string(which)
209	                               + " for ----->\n" + hint.to_pp_string());
210	    }
211	
212	    // create a unique hash for the device address
213	    device_addr_t dev_addr;
214	    make_t maker;
215	    std::tie(dev_addr, maker) = dev_addr_makers.at(which);
216	    size_t dev_hash           = hash_device_addr(dev_addr);
217	    UHD_LOGGER_TRACE("UHD") << "Device hash: " << dev_hash;
218	
219	    // copy keys that were in hint but not in dev_addr
220	    // this way, we can pass additional transport arguments
221	    for (const std::string& key : hint.keys()) {
222	        if (not dev_addr.has_key(key))
223	            dev_addr[key] = hint[key];
224	    }
225	
226	    // map device address hash to created devices
227	    static uhd::dict<size_t, std::weak_ptr<device>> hash_to_device;
228	
229	    // try to find an existing device
230	    if (hash_to_device.has_key(dev_hash)) {
231	        if (device::sptr p = hash_to_device[dev_hash].lock()) {
232	            return p;
233	        }
234	    }
235	
236	    // Add keys from the config files (note: the user-defined keys will
237	    // always be applied, see also get_usrp_args()
238	    // Then, create and register a new device.
239	    device::sptr dev         = maker(prefs::get_usrp_args(dev_addr));
240	    hash_to_device[dev_hash] = dev;
241	    return dev;
242	}
